#!/usr/bin/env bash
# Generated by prepare_cd38_external_tool_inputs.py
# Run external fpocket commands for CD38 target structures.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

if ! command -v fpocket >/dev/null 2>&1; then
  echo "Missing fpocket executable. Install fpocket or add it to PATH." >&2
  exit 127
fi

# 3ROP
RUN_DIR="$SCRIPT_DIR/fpocket_runs/3ROP"
(cd "$RUN_DIR" && fpocket -f "3ROP.pdb")

# 4OGW
RUN_DIR="$SCRIPT_DIR/fpocket_runs/4OGW"
(cd "$RUN_DIR" && fpocket -f "4OGW.pdb")

# 3F6Y
RUN_DIR="$SCRIPT_DIR/fpocket_runs/3F6Y"
(cd "$RUN_DIR" && fpocket -f "3F6Y.pdb")

